// 1. Capturamos la hora actual y configuramos el umbral
const ahora = new Date();
const UMBRAL_DIAS = 1;

// Variables para armar el reporte
let cuerpoReporte = "";
let totalCriticos = 0;

// Función auxiliar para traducir el formato de GDocument
function parsearFechaGDoc(fechaString) {
  const fechaPartes = fechaString.split(" ");
  const [dia, mes, anio] = fechaPartes[0].split("-").map(Number);
  let [hora, minutos] = fechaPartes[1].split(":").map(Number);
  const ampm = fechaPartes[2];

  if (ampm === "PM" && hora !== 12) hora += 12;
  if (ampm === "AM" && hora === 12) hora = 0;

  return new Date(anio, mes - 1, dia, hora, minutos);
}

// 2. Recorremos todos los tickets que salieron del Split Out
for (const item of $input.all()) {
  const ticket = item.json;

  if (!ticket.fechaInicio) continue;

  const fechaCreacion = parsearFechaGDoc(ticket.fechaInicio);
  const diferenciaMs = ahora - fechaCreacion;

  const msEnUnDia = 86400000;
  const msEnUnaHora = 3600000;

  const diasEnEspera = Math.floor(diferenciaMs / msEnUnDia);
  const horasEnEspera = Math.floor((diferenciaMs % msEnUnDia) / msEnUnaHora);

  // 3. Si cumple la condición, lo añadimos a las líneas del reporte
  if (diasEnEspera >= UMBRAL_DIAS) {
    totalCriticos++;

    // Extraemos la sede de forma segura por si no existe en el JSON
    const sede = ticket.busqueda?.direccion_de_soporte || "Sede no especificada";
    const empresa = ticket.busqueda?.cliente || "Cliente no especificado";

    cuerpoReporte += `• 🎫 *Radicado:* \`${ticket.radicado}\`\n`;
    cuerpoReporte += `  🏢 *Empresa:* ${empresa}\n`;
    cuerpoReporte += `  📍 *Sede:* ${sede}\n`;
    cuerpoReporte += `  ⏳ *Espera:* ${diasEnEspera} día(s) y ${horasEnEspera} hora(s)\n`;
    cuerpoReporte += `─────────────────────\n`;
  }
}

// 4. Diseñamos el encabezado y cierre del mensaje según el resultado
let mensajeFinal = "";

if (totalCriticos > 0) {
  mensajeFinal = `📊 *REPORTE DIARIO: TICKETS CRÍTICOS SIN ASIGNAR* 📊\n\n`;
  mensajeFinal += `⚠️ Se encontraron *${totalCriticos}* requerimientos con más de ${UMBRAL_DIAS} día de retraso en la bandeja global.\n\n`;
  mensajeFinal += cuerpoReporte;
  mensajeFinal += `\n_🔧 Por favor, el equipo técnico ingresar a GDocument para gestionar estos casos prioritarios._\n🔗 *Tomar flujo crítico:* https://produccion.gdocument.co/login`;
} else {
  mensajeFinal = `📊 *REPORTE DIARIO: TICKETS CRÍTICOS SIN ASIGNAR* 📊\n\n`;
  mensajeFinal += `✅ *¡Excelente!* No se encontraron tickets retrasados con más de ${UMBRAL_DIAS} día en la bandeja global. Todo el flujo está al día.`;
}

// 5. Retornamos UN SOLO objeto con todo el texto consolidado
return [{ json: { reporteMarkdown: mensajeFinal, total: totalCriticos } }];
